from xml.etree import ElementTree as ET
import lxml.etree as etree

def process_soap_request(xml):
    try:
        # Parse the SOAP request using lxml
        parsed = etree.fromstring(xml)
        
        # Extract namespaces
        namespaces = {'s': 'http://schemas.xmlsoap.org/soap/envelope/'}
        
        # Find the SOAP Body element
        body_element = parsed.find('.//s:Body', namespaces=namespaces)
        
        if body_element is not None:
            return ET.tostring(body_element, encoding='unicode')
    except Exception as e:
        print("Error processing SOAP request: ", str(e))